use std::collections::{HashMap, VecDeque};

fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }

    const MAX: usize = 1_000_000;
    let sieve = generate_sieve(MAX);

    let mut prime_to_indices = HashMap::new();
    for (j, &num) in nums.iter().enumerate() {
        let num_u64 = num as u64;
        let factors = get_prime_factors(num_u64, &sieve);
        for p in factors {
            prime_to_indices.entry(p).or_insert_with(Vec::new).push(j);
        }
    }

    let mut distance = vec![-1; n];
    let mut queue = VecDeque::new();
    queue.push_back(0);
    distance[0] = 0;

    while let Some(i) = queue.pop_front() {
        if i == n - 1 {
            return distance[i] as i64;
        }

        let num = nums[i];
        if num > 0 && num <= MAX as i64 && sieve[num as usize] {
            let p = num;
            if let Some(indices) = prime_to_indices.get(&p) {
                for &j in indices {
                    if j != i && distance[j] == -1 {
                        distance[j] = distance[i] + 1;
                        queue.push_back(j);
                    }
                }
            }
        }

        for &neighbor in &[i - 1, i + 1] {
            if neighbor >= 0 && neighbor < n && distance[neighbor] == -1 {
                distance[neighbor] = distance[i] + 1;
                queue.push_back(neighbor);
            }
        }
    }

    -1
}

